// Script Continued Below
var gr_fix_privacy = new GlideRecord("x_153465_discovert_route_task_instance");

gr_fix_privacy.addEncodedQuery("u_privacyNSAMEASprimary_office.u_top_ou.u_organizational_privacy");
gr_fix_privacy.query();

var countPrivacyMismatches = 0;
var countPrivacyMismatchFixes = 0;
while(gr_fix_privacy.next()){
  countPrivacyMismatches++;
  var previousPrivacy = gr_fix_privacy.getValue("u_privacy");
  // here we update them...
  gr_fix_privacy.u_privacy = gr_fix_privacy.primary_office.u_top_ou.u_organizational_privacy;

  var newPrivacy = gr_fix_privacy.u_privacy;

  gs.info("Tasker 2.8.4 - Fix Script - updating Tasker Template Privacy Mismatch for gr_fix_privacy.number: " + gr_fix_privacy.number + " - from - previousPrivacy: " + previousPrivacy + " - to - newPrivacy: " + newPrivacy); 
  gr_fix_privacy.autoSysFields(false);
  gr_fix_privacy.update("Fix Script - updating Tasker Template Privacy");
  countPrivacyMismatchFixes++;
}

gs.info("Tasker 2.8.4 - Fix Script - updating Tasker Template Privacy Mismatch - Found [" + countPrivacyMismatches + "] " + " - Corrected [" + countPrivacyMismatchFixes + "]");
